  // A stub iterator for providing controlled sequences of CssToken
  static class StubIterator implements CssTokenIterator {
    private final List<CssToken> tokens;
    private int idx = 0;
    public CssToken last;
    public StubIterator(List<CssToken> tokens) { this.tokens = tokens; }
    @Override public boolean hasNext() { return idx < tokens.size(); }
    @Override public boolean hasNext(java.util.function.Predicate<CssToken> f) { return hasNext(); }
    @Override public CssToken next() {
      last = tokens.get(idx++);
      return last;
    }
    @Override public CssToken next(java.util.function.Predicate<CssToken> f) { return next(); }
    @Override public CssToken next(java.util.function.Predicate<CssToken> f, int skip) { return next(); }
    @Override public CssToken peek() { return idx < tokens.size() ? tokens.get(idx) : null; }
    @Override public int index() { return idx - 1; }
    @Override public List<CssToken> getList() { return tokens; }
    @Override public Object filter() { return null; }
    @Override public Object get() { return null; }
    @Override public void remove() { throw new UnsupportedOperationException(); }
  }

  // Helpers to create mock tokens of given type
  private CssToken mockToken(Type type, char ch, String chars) {
    CssToken tk = mock(CssToken.class);
    when(tk.type).thenReturn(type);
    when(tk.getChar()).thenReturn(ch);
    when(tk.getChars()).thenReturn(chars);
    when(tk.toString()).thenReturn(chars);
    return tk;
  }

  /**
   * TC01: No tokens => hasNext(FILTER_S_CMNT_CDO_CDC)=false immediately.
   */
  @Test
  @DisplayName("No tokens from scan results in immediate endDocument (loop-0, branch:false)")
  void test_TC01() throws Exception {
    Reader rdr = new StringReader("");
    CssErrorHandler err = mock(CssErrorHandler.class);
    CssContentHandler doc = mock(CssContentHandler.class);
    // Stub parser to return empty iterator: loop-0
    CssParser parser = new CssParser() {
      @Override protected CssTokenIterator scan(Reader r, String id, CssErrorHandler e) {
        // no tokens causes hasNext(filter)=false
        return new StubIterator(Arrays.asList());
      }
    };
    parser.parse(rdr, "sys", err, doc);
    // expect startDocument and endDocument exactly once
    verify(doc, times(1)).startDocument();
    verify(doc, times(1)).endDocument();
  }

  /**
   * TC02: Single ATKEYWORD token triggers handleAtRule then endDocument.
   */
  @Test
  @DisplayName("Single ATKEYWORD token triggers handleAtRule then endDocument (loop-1, branch:ATKEYWORD)")
  void test_TC02() throws Exception {
    Reader rdr = new StringReader("");
    CssErrorHandler err = mock(CssErrorHandler.class);
    CssContentHandler doc = mock(CssContentHandler.class);
    CssToken atTk = mockToken(Type.ATKEYWORD, '@', "@at");
    // Iterator yields ATKEYWORD then ends
    StubIterator iter = new StubIterator(Arrays.asList(atTk));
    // Spy parser to count handleAtRule calls
    CssParser parser = spy(new CssParser() {
      @Override protected CssTokenIterator scan(Reader r, String id, CssErrorHandler e) {
        return iter;
      }
    });
    doNothing().when(parser).handleAtRule(any(), any(), eq(doc), eq(err));
    parser.parse(rdr, "id", err, doc);
    verify(parser, times(1)).handleAtRule(atTk, iter, doc, err);
    verify(doc, times(1)).startDocument();
    verify(doc, times(1)).endDocument();
  }

  /**
   * TC03: Single non-ATKEYWORD token triggers handleRuleSet then endDocument.
   */
  @Test
  @DisplayName("Single non-ATKEYWORD token triggers handleRuleSet then endDocument (loop-1, branch:non-ATKEYWORD)")
  void test_TC03() throws Exception {
    Reader rdr = new StringReader("");
    CssErrorHandler err = mock(CssErrorHandler.class);
    CssContentHandler doc = mock(CssContentHandler.class);
    CssToken idTk = mockToken(Type.IDENT, 'a', "prop");
    StubIterator iter = new StubIterator(Arrays.asList(idTk));
    CssParser parser = spy(new CssParser() {
      @Override protected CssTokenIterator scan(Reader r, String id, CssErrorHandler e) {
        return iter;
      }
    });
    doNothing().when(parser).handleRuleSet(any(), any(), eq(doc), eq(err));
    parser.parse(rdr, "id", err, doc);
    verify(parser, times(1)).handleRuleSet(idTk, iter, doc, err);
    verify(doc, times(1)).startDocument();
    verify(doc, times(1)).endDocument();
  }

