  /**
   * TC06: IOException from scan() is propagated.
   */
  @Test
  @DisplayName("IOException from scan() is propagated (exception path)")
  void test_TC06() {
    CssParser parser = new CssParser() {
      @Override protected CssTokenIterator scan(Reader r, String id, CssErrorHandler e) throws IOException {
        throw new IOException("fail-scan");
      }
    };
    assertThrows(IOException.class, () ->
      parser.parse(new StringReader(""), "id", mock(CssErrorHandler.class), mock(CssContentHandler.class))
    );
