  /**
   * TC07: CssException from scan() is propagated.
   */
  @Test
  @DisplayName("CssException from scan() is propagated (exception path)")
  void test_TC07() {
    CssParser parser = new CssParser() {
      @Override protected CssTokenIterator scan(Reader r, String id, CssErrorHandler e) throws CssException {
