  /**
   * TC08: PrematureEOFException in handleRuleSet breaks loop and ends document.
   */
  @Test
  @DisplayName("PrematureEOFException in handleRuleSet breaks loop and ends document (exception branch)")
  void test_TC08() throws Exception {
    Reader rdr = new StringReader("");
    CssErrorHandler err = mock(CssErrorHandler.class);
    CssContentHandler doc = mock(CssContentHandler.class);
    CssToken idTk = mockToken(Type.IDENT, 'a', "prop");
    StubIterator iter = new StubIterator(Arrays.asList(idTk));
    CssParser parser = spy(new CssParser() {
      @Override protected CssTokenIterator scan(Reader r, String id, CssErrorHandler e) {
        return iter;
      }
    });
    doThrow(new PrematureEOFException()).when(parser).handleRuleSet(idTk, iter, doc, err);
    // Should swallow PrematureEOFException inside parse and endDocument
    parser.parse(rdr, "id", err, doc);
    verify(doc, times(1)).startDocument();
    verify(doc, times(1)).endDocument();
  }

  /**
   * TC09: CssException from handleAtRule propagates.
   */
  @Test
  @DisplayName("CssException from handleAtRule propagates (exception path)")
  void test_TC09() throws Exception {
    Reader rdr = new StringReader("");
    CssErrorHandler err = mock(CssErrorHandler.class);
    CssContentHandler doc = mock(CssContentHandler.class);
    CssToken atTk = mockToken(Type.ATKEYWORD, '@', "@at");
    StubIterator iter = new StubIterator(Arrays.asList(atTk));
    CssParser parser = spy(new CssParser() {
      @Override protected CssTokenIterator scan(Reader r, String id, CssErrorHandler e) {
        return iter;
      }
    });
    doThrow(new CssGrammarException(null, null, null, "bad")).when(parser).handleAtRule(atTk, iter, doc, err);
